// Парсим Alertmanager payload
const body = $input.first().json.body || $input.first().json;
const alerts = body.alerts || [];
const results = [];

for (const alert of alerts) {
  const isFiring = alert.status === 'firing';
  const emoji = isFiring ? '🔴' : '✅';
  const name = alert.labels?.alertname || 'Unknown';
  const ns = alert.labels?.namespace || 'cluster';
  const severity = alert.labels?.severity || 'info';
  const summary = alert.annotations?.summary || '';
  const desc = alert.annotations?.description || '';
  const instance = alert.labels?.instance || '';

  const sevEmoji = severity === 'critical' ? '🚨' : severity === 'warning' ? '⚠️' : 'ℹ️';

  let msg = `${emoji} <b>${name}</b>\n`;
  msg += `📍 Namespace: <code>${ns}</code>\n`;
  msg += `${sevEmoji} Severity: <b>${severity}</b>\n`;
  if (instance) msg += `🖥️ Instance: <code>${instance}</code>\n`;
  if (summary) msg += `💬 ${summary}\n`;
  if (desc) msg += `📋 ${desc}\n`;
  if (!isFiring) msg += `\n✅ <i>Alert resolved</i>`;

  results.push({ json: { message: msg, alertname: name, status: alert.status } });
}

if (results.length === 0) {
  return [{ json: { message: '✅ All alerts cleared', alertname: 'none', status: 'resolved' } }];
}

return results;
